// src/components/MisinformationChecker.js
import React, { useState } from "react";
import axios from "axios";

const API_URL = "http://127.0.0.1:5000";

function MisinformationChecker() {
  const [text, setText] = useState("");
  const [result, setResult] = useState(null);
  const [error, setError] = useState("");
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (event) => {
    event.preventDefault();
    if (text.length < 50) {
      setError("Please enter at least 50 characters for a reliable analysis.");
      return;
    }
    setIsLoading(true);
    setError("");
    setResult(null);
    try {
      const response = await axios.post(`${API_URL}/predict/misinformation`, {
        text,
      });
      setResult(response.data);
    } catch (err) {
      setError(
        "API Error. Please check your Gemini API key in the backend and restart the server."
      );
    } finally {
      setIsLoading(false);
    }
  };

  // Custom styles for verdicts
  const getVerdictClass = (verdict) => {
    switch (String(verdict).toUpperCase()) {
      case "FAKE":
        return "result-deepfake";
      case "MISLEADING":
        return "result-misleading"; // You can style this in index.css
      case "REAL":
        return "result-real";
      default:
        return "";
    }
  };

  return (
    <div className="detector-container">
      <h2 style={{ textAlign: "center" }}>📰 Misinformation Checker</h2>
      <form onSubmit={handleSubmit} className="detector-form">
        <textarea
          rows="12"
          value={text}
          onChange={(e) => setText(e.target.value)}
          placeholder="Paste a news article or text here..."
          style={{
            width: "90%",
            padding: "1rem",
            fontSize: "1rem",
            borderRadius: "8px",
            border: "1px solid #ccc",
          }}
        />
        <button
          type="submit"
          className="btn"
          disabled={isLoading || text.length < 50}
        >
          {isLoading ? "Analyzing with Gemini..." : "Check Text"}
        </button>
      </form>

      {isLoading && (
        <div className="spinner-container">
          <div className="spinner"></div>
        </div>
      )}
      {error && (
        <p style={{ color: "var(--danger-color)", textAlign: "center" }}>
          {error}
        </p>
      )}

      {result && (
        <div className={`result-card ${getVerdictClass(result.verdict)}`}>
          <h4>VERDICT: {result.verdict || "UNKNOWN"}</h4>
          <p>Confidence: **{(result.confidence_score * 100).toFixed(2)}%**</p>
          <hr style={{ border: "none", borderTop: "1px solid #ddd" }} />
          <p style={{ textAlign: "left" }}>
            <strong>Summary:</strong> {result.summary || "N/A"}
          </p>
        </div>
      )}
    </div>
  );
}

export default MisinformationChecker;
